sql:
SELECT campaign_name, campaign_manager
FROM marketing_campaigns
WHERE start_date < '2020-01-01';

SELECT city, state, sales_region_id, store_manager, phone_number, street_address
FROM stores
WHERE store_id = 0;

SELECT campaign_name, budget
FROM marketing_campaigns
WHERE campaign_id > 5;

external_knowledge:
- 'Treasure chest' is a metaphor for the stores that hold wealth;
- 'Golden fruits' symbolize the revenue, representing the profits earned;
- 'Silver seeds' represents the expansion costs, symbolizing the investments or expenses made to grow;
- The period from the 'dawn of 2020 to the twilight of 2022' refers to the date range specified in the SQL query (2020-01-01 to 2022-12-31).

sql:
SELECT AVG(revenue) AS Average_Sales_Performance
FROM sales_performance
WHERE store_id = 1 AND strftime('%Y-%m', date) = '2022-02';

SELECT COUNT(*) AS number_of_expansions
FROM store_expansion_history
WHERE store_id = 0;

SELECT sales_channel, COUNT(*)
FROM sales_performance
GROUP BY sales_channel;

SELECT store_id
FROM sales_performance
WHERE revenue = (SELECT MAX(revenue) FROM sales_performance);
